body:
can't generate btor2 file for pulpissimo SoC's SRAM due to performance issues

## Steps to reproduce the issue

<!-- *Provide instructions for reproducing the issue. Make sure to include all necessary source files. (You can simply drag&drop a .zip file into the issue editor.)*

Also, make sure that the issue is actually reproducable in current git
master of Yosys.

See https://stackoverflow.com/help/mcve for some information on how to
create a Minimal, Complete, and Verifiable example (MCVE).

Please do not waste our time with issues that lack sufficient information
to reproduce the issue easily. We will simply close those issues.

Contact https://www.yosyshq.com/ if you need commercial support for Yosys. -->

I want to get the btor2 file for [pulp's SRAM](https://github.com/pulp-platform/tech_cells_generic/blob/master/src/rtl/tc_sram.sv), so I convert it to a verilog file using [sv2v](https://github.com/zachjs/sv2v) first, then I feed it to yosys.

(yosys version 0.9 (git sha1 1979e0b))

sv2v-generated tc_sram.v
```verilog
module tc_sram (
	clk_i,
	rst_ni,
	req_i,
	we_i,
	addr_i,
	wdata_i,
	be_i,
	rdata_o
);
	parameter [31:0] NumWords = 32'd1024;
	parameter [31:0] DataWidth = 32'd128;
	parameter [31:0] ByteWidth = 32'd8;
	parameter [31:0] NumPorts = 32'd2;
	parameter [31:0] Latency = 32'd1;
	parameter SimInit = "none";
	parameter [0:0] PrintSimCfg = 1'b0;
	parameter [31:0] AddrWidth = (NumWords > 32'd1 ? $clog2(NumWords) : 32'd1);
	parameter [31:0] BeWidth = ((DataWidth + ByteWidth) - 32'd1) / ByteWidth;
	input wire clk_i;
	input wire rst_ni;
	input wire [NumPorts - 1:0] req_i;
	input wire [NumPorts - 1:0] we_i;
	input wire [(NumPorts * AddrWidth) - 1:0] addr_i;
	input wire [(NumPorts * DataWidth) - 1:0] wdata_i;
	input wire [(NumPorts * BeWidth) - 1:0] be_i;
	output reg [(NumPorts * DataWidth) - 1:0] rdata_o;
	reg [DataWidth - 1:0] sram [NumWords - 1:0];
	reg [(NumPorts * AddrWidth) - 1:0] r_addr_q;
	reg [(NumWords * DataWidth) - 1:0] init_val;
	initial begin : proc_sram_init
		begin : sv2v_autoblock_1
			reg [31:0] i;
			for (i = 0; i < NumWords; i = i + 1)
				begin : sv2v_autoblock_2
					reg [31:0] j;
					for (j = 0; j < DataWidth; j = j + 1)
						case (SimInit)
							"zeros": init_val[(i * DataWidth) + j] = 1'b0;
							"ones": init_val[(i * DataWidth) + j] = 1'b1;
							"random": init_val[(i * DataWidth) + j] = $urandom();
							default: init_val[(i * DataWidth) + j] = 1'bx;
						endcase
				end
		end
	end
	reg [((NumPorts * Latency) * DataWidth) - 1:0] rdata_q;
	reg [((NumPorts * Latency) * DataWidth) - 1:0] rdata_d;
	generate
		if (Latency == 32'd0) begin : gen_no_read_lat
			genvar i;
			for (i = 0; i < NumPorts; i = i + 1) begin : gen_port
				wire [DataWidth:1] sv2v_tmp_2E95D;
				assign sv2v_tmp_2E95D = (req_i[i] && !we_i[i] ? sram[addr_i[i * AddrWidth+:AddrWidth]] : sram[r_addr_q[i * AddrWidth+:AddrWidth]]);
				always @(*) rdata_o[i * DataWidth+:DataWidth] = sv2v_tmp_2E95D;
			end
		end
		else begin : gen_read_lat
			always @(*) begin : sv2v_autoblock_3
				reg [31:0] i;
				for (i = 0; i < NumPorts; i = i + 1)
					begin
						rdata_o[i * DataWidth+:DataWidth] = rdata_q[(i * Latency) * DataWidth+:DataWidth];
						begin : sv2v_autoblock_4
							reg [31:0] j;
							for (j = 0; j < (Latency - 1); j = j + 1)
								rdata_d[((i * Latency) + j) * DataWidth+:DataWidth] = rdata_q[((i * Latency) + (j + 1)) * DataWidth+:DataWidth];
						end
						rdata_d[((i * Latency) + (Latency - 1)) * DataWidth+:DataWidth] = (req_i[i] && !we_i[i] ? sram[addr_i[i * AddrWidth+:AddrWidth]] : sram[r_addr_q[i * AddrWidth+:AddrWidth]]);
					end
			end
		end
	endgenerate
	always @(posedge clk_i or negedge rst_ni)
		if (!rst_ni) begin
			begin : sv2v_autoblock_5
				reg [31:0] i;
				for (i = 0; i < NumWords; i = i + 1)
					sram[i] <= init_val[i * DataWidth+:DataWidth];
			end
			begin : sv2v_autoblock_6
				reg signed [31:0] i;
				for (i = 0; i < NumPorts; i = i + 1)
					begin
						r_addr_q[i * AddrWidth+:AddrWidth] <= {AddrWidth {1'b0}};
						if (Latency != 32'd0) begin : sv2v_autoblock_7
							reg [31:0] j;
							for (j = 0; j < Latency; j = j + 1)
								rdata_q[((i * Latency) + j) * DataWidth+:DataWidth] <= init_val[{AddrWidth {1'b0}} * DataWidth+:DataWidth];
						end
					end
			end
		end
		else begin
			begin : sv2v_autoblock_8
				reg [31:0] i;
				for (i = 0; i < NumPorts; i = i + 1)
					if (Latency != 0) begin : sv2v_autoblock_9
						reg [31:0] j;
						for (j = 0; j < Latency; j = j + 1)
							rdata_q[((i * Latency) + j) * DataWidth+:DataWidth] <= rdata_d[((i * Latency) + j) * DataWidth+:DataWidth];
					end
			end
			begin : sv2v_autoblock_10
				reg [31:0] i;
				for (i = 0; i < NumPorts; i = i + 1)
					if (req_i[i])
						if (we_i[i]) begin : sv2v_autoblock_11
							reg [31:0] j;
							for (j = 0; j < DataWidth; j = j + 1)
								if (be_i[(i * BeWidth) + (j / ByteWidth)])
									sram[addr_i[i * AddrWidth+:AddrWidth]][j] <= wdata_i[(i * DataWidth) + j];
						end
						else
							r_addr_q[i * AddrWidth+:AddrWidth] <= addr_i[i * AddrWidth+:AddrWidth];
			end
		end
	initial begin : p_assertions
		
	end
	initial begin : p_sim_hello
		if (PrintSimCfg) begin
			$display("#################################################################################");
			$display("tc_sram functional instantiated with the configuration:");
			$display("Instance: %m");
			$display("Number of ports   (dec): %0d", NumPorts);
			$display("Number of words   (dec): %0d", NumWords);
			$display("Address width     (dec): %0d", AddrWidth);
			$display("Data width        (dec): %0d", DataWidth);
			$display("Byte width        (dec): %0d", ByteWidth);
			$display("Byte enable width (dec): %0d", BeWidth);
			$display("Latency Cycles    (dec): %0d", Latency);
			$display("Simulation init   (str): %0s", SimInit);
			$display("#################################################################################");
		end
	end
	genvar i;
endmodule
```
the script I'm using
```
read_verilog -formal ./tc_sram.v
prep -top tc_sram;
hierarchy -check;
memory -nomap;
flatten;
clk2fflogic;
setundef -undriven -expose;
write_btor tc_ram.btor2
```
## Expected behavior
no overhead, don't replace sram with registers
<!-- *Please describe the behavior you would have expected from the tool.* -->

## Actual behavior
yosys says
> Warning: Replacing memory \sram with list of registers. See ./tc_sram.v:79`

and keeps running. yosys did terminate if I change `NumWords` and `DataWidth` smaller.

<!-- *Please describe how the behavior you see differs from the expected behavior.* -->

